  ctx.fillText('Thu', 32, 2);
  ctx.fillStyle = '#c0c0c0';
  ctx.font = '14px Gothic';
  ctx.textAlign = 'left';
  ctx.fillText('75°/58°', 80, 2);
  ctx.fillStyle = '#c0c0c0';
  ctx.beginPath();
  ctx.arc(18, 14, 8, 0, 2 * Math.PI, false);
  ctx.fill();
  ctx.fillStyle = '#ffffff';
  ctx.font = '14px bold Gothic';
  ctx.textAlign = 'left';
  ctx.fillText('Fri', 32, 2);
